// Extract missing SKUs and order context
const body = $input.first().json.body;
const missingSkus = body.missing_skus || [];
const orderContext = body.order_context || {};

if (!Array.isArray(missingSkus) || missingSkus.length === 0) {
  return [{
    json: {
      scraped_products: [],
      failed_skus: [],
      scraping_duration: 0,
      message: 'No missing SKUs to scrape'
    }
  }];
}

// Create individual items for each missing SKU
return missingSkus.map(sku => ({
  json: {
    sku: sku,
    order_id: orderContext.order_id,
    scrape_start: new Date().toISOString()
  }
}));

// Match SKU to vendor based on SKU pattern or vendor name
const sku = $node['Extract Missing SKUs'].json.sku;
const vendors = $input.all().map(v => v.json);

// Try to match vendor by SKU prefix pattern
let matchedVendor = null;

for (const vendor of vendors) {
  // Check if vendor has SKU prefix pattern
  if (vendor.sku_prefix && sku.startsWith(vendor.sku_prefix)) {
    matchedVendor = vendor;
    break;
  }

  // Check if vendor name is in SKU
  if (vendor.vendor_name && sku.toLowerCase().includes(vendor.vendor_name.toLowerCase().replace(/\s+/g, '-'))) {
    matchedVendor = vendor;
    break;
  }
}

if (!matchedVendor) {
  return [{
    json: {
      sku: sku,
      vendor_found: false,
      error: `Cannot determine vendor for SKU: ${sku}`,
      scrape_failed: true
    }
  }];
}

return [{
  json: {
    sku: sku,
    vendor_found: true,
    vendor_id: matchedVendor.vendor_id,
    vendor_name: matchedVendor.vendor_name,
    tier_used: matchedVendor.tier_used,
    data_source_type: matchedVendor.data_source_type,
    data_source_url: matchedVendor.data_source_url,
    scrape_start: $node['Extract Missing SKUs'].json.scrape_start
  }
}];

// Process scraper response
const response = $input.first().json;
const originalSku = $node['Match SKU to Vendor'].json.sku;
const vendorId = $node['Match SKU to Vendor'].json.vendor_id;
const tier = $node['Match SKU to Vendor'].json.tier_used;
const scrapeStart = new Date($node['Match SKU to Vendor'].json.scrape_start);
const scrapeEnd = new Date();
const duration = scrapeEnd - scrapeStart;

// Check if scraping succeeded
if (response.error || !response.sku) {
  return [{
    json: {
      sku: originalSku,
      scrape_success: false,
      error: response.error || 'Unknown scraping error',
      duration_ms: duration,
      tier_used: tier
    }
  }];
}

// Scraping succeeded - prepare product data
return [{
  json: {
    ...response,
    sku: response.sku || originalSku,
    vendor_id: vendorId,
    source_tier: tier,
    scrape_success: true,
    duration_ms: duration,
    scraped_at: scrapeEnd.toISOString()
  }
}];

