const duration = scrapeEnd - scrapeStart;

// Check if scraping succeeded
if (response.error || !response.sku) {
  return [{
    json: {
      sku: originalSku,
      scrape_success: false,
      error: response.error || 'Unknown scraping error',
      duration_ms: duration,
      tier_used: tier
    }
  }];
}

// Scraping succeeded - prepare product data
return [{
  json: {
    ...response,
    sku: response.sku || originalSku,
    vendor_id: vendorId,
    source_tier: tier,
    scrape_success: true,
    duration_ms: duration,
    scraped_at: scrapeEnd.toISOString()
  }
}];

// Mark as failed scrape
const failedItem = $input.first().json;

return [{
  json: {
    ...failedItem,
    saved_to_db: false
  }
}];

// Aggregate on-demand scraping results
const allResults = $input.all();

const scrapedProducts = allResults.filter(r => r.json.scrape_success);
const failedSkus = allResults.filter(r => !r.json.scrape_success).map(r => r.json.sku);

const totalDuration = allResults.reduce((sum, r) => sum + (r.json.duration_ms || 0), 0);
const avgDuration = allResults.length > 0 ? totalDuration / allResults.length : 0;

return [{
  json: {
    scraped_products: scrapedProducts.map(p => p.json),
    failed_skus: failedSkus,
    total_attempted: allResults.length,
    successful_scrapes: scrapedProducts.length,
    failed_scrapes: failedSkus.length,
    success_rate: allResults.length > 0 ? (scrapedProducts.length / allResults.length) : 0,
    total_duration_ms: totalDuration,
    avg_duration_ms: avgDuration,
    timestamp: new Date().toISOString()
  }
}];
